## mylib — Device Monitoring Library (nim-brokers FFI API example)
## ================================================================
## Demonstrates a realistic Nim dynamic library exposing a device
## monitoring service through C-callable interfaces generated by the
## broker FFI API system.
##
## Capabilities:
## - Add / remove / query individual devices
## - List all registered devices (returns an array of structs)
## - Receive real-time event callbacks for device status changes
##   and device discovery notifications
##
## Build (from repo root):
##   nimble buildFfiExample
##
## Produces: examples/ffiapi/nimlib/build/libmylib.{so,dylib,dll} + mylib.h

{.push raises: [].}

import brokers/[event_broker, request_broker, broker_context, api_library]

# ---------------------------------------------------------------------------
# Shared item types (used in seq[T] request and result fields)
# ---------------------------------------------------------------------------

## DeviceInfo — flat struct describing a single device.
## Plain Nim type: auto-registered when referenced in broker macros.
type DeviceInfo* = object
  deviceId*: int64
  name*: string
  deviceType*: string
  address*: string
  online*: bool

## AddDeviceSpec — FFI-safe batch input item for AddDevice.
type AddDeviceSpec* = object
  name*: string
  deviceType*: string
  address*: string

## DeviceStatus — enum for device health state.
## Exercises: enum type → C typedef enum, ABI as int32_t.
type DeviceStatus* = enum
  dsUnknown = 0
  dsOnline = 1
  dsOffline = 2
  dsError = 3

## Timestamp — distinct int64 for type-safe timestamp values (milliseconds since epoch).
## Exercises: distinct type → C typedef int64_t Timestamp.
type Timestamp* = distinct int64

## SensorId — distinct int32 for type-safe sensor identifiers.
## Exercises: distinct type → C typedef int32_t SensorId.
type SensorId* = distinct int32

# ---------------------------------------------------------------------------
# Request Brokers
# ---------------------------------------------------------------------------

## InitializeRequest: called after mylib_createContext() to configure the monitoring engine.
RequestBroker(API):
  type InitializeRequest = object
    configPath*: string
    initialized*: bool

  proc signature*(
    configPath: string
  ): Future[Result[InitializeRequest, string]] {.async.}

## ShutdownRequest: called by mylib_shutdown() to tear down state.
RequestBroker(API):
  type ShutdownRequest = object
    status*: int32

  proc signature*(): Future[Result[ShutdownRequest, string]] {.async.}

## AddDevice: register one or more devices for monitoring.
RequestBroker(API):
  type AddDevice = object
    devices*: seq[DeviceInfo]
    success*: bool

  proc signature*(
    devices: seq[AddDeviceSpec]
  ): Future[Result[AddDevice, string]] {.async.}

## RemoveDevice: stop monitoring a device and remove it.
RequestBroker(API):
  type RemoveDevice = object
    success*: bool

  proc signature*(deviceId: int64): Future[Result[RemoveDevice, string]] {.async.}

## GetDevice: query a single device by ID.
RequestBroker(API):
  type GetDevice = object
    deviceId*: int64
    name*: string
    deviceType*: string
    address*: string
    online*: bool

  proc signature*(deviceId: int64): Future[Result[GetDevice, string]] {.async.}

## ListDevices: return all registered devices as an array.
RequestBroker(API):
  type ListDevices = object
    devices*: seq[DeviceInfo]

  proc signature*(): Future[Result[ListDevices, string]] {.async.}

## GetSensorData: return raw binary sensor data for a device.
## Exercises: seq[byte] (seq[primitive]) → uint8_t* + int32_t count in C.
RequestBroker(API):
  type GetSensorData = object
    sensorId*: SensorId
    rawData*: seq[byte]
    status*: DeviceStatus

  proc signature*(deviceId: int64): Future[Result[GetSensorData, string]] {.async.}

## GetDeviceTags: return string labels associated with a device.
## Exercises: seq[string] → char** + int32_t count in C.
RequestBroker(API):
  type GetDeviceTags = object
    tags*: seq[string]

  proc signature*(deviceId: int64): Future[Result[GetDeviceTags, string]] {.async.}

## GetDeviceCapabilities: return a fixed-size capability vector.
## Exercises: array[4, int32] → int32_t caps[4] in C.
RequestBroker(API):
  type GetDeviceCapabilities = object
    capabilities*: array[4, int32]
    capturedAt*: Timestamp

  proc signature*(
    deviceId: int64
  ): Future[Result[GetDeviceCapabilities, string]] {.async.}

# ---------------------------------------------------------------------------
# Event Brokers
# ---------------------------------------------------------------------------

## DeviceStatusChanged: emitted when a device's online status changes.
EventBroker(API):
  type DeviceStatusChanged = object
    deviceId*: int64
    name*: string
    online*: bool
    timestampMs*: int64

## DeviceDiscovered: emitted when auto-discovery finds a new device.
EventBroker(API):
  type DeviceDiscovered = object
    deviceId*: int64
    name*: string
    deviceType*: string
    address*: string

## SensorAlert: emitted when a sensor reading crosses a threshold.
## Exercises: enum (DeviceStatus) and distinct (SensorId) in event fields.
EventBroker(API):
  type SensorAlert = object
    sensorId*: SensorId
    deviceId*: int64
    status*: DeviceStatus
    timestampMs*: Timestamp

# ---------------------------------------------------------------------------
# Library internals (provider implementations)
# ---------------------------------------------------------------------------

type Device = object
  id: int64
  name: string
  deviceType: string
  address: string
  online: bool

var gDevices {.threadvar.}: seq[Device]
var gNextDeviceId {.threadvar.}: int64
var gNextSensorId {.threadvar.}: int32
var gConfigPath {.threadvar.}: string
var gInitialized {.threadvar.}: bool
var gProviderCtx {.threadvar.}: BrokerContext

proc nowMs(): int64 =
  int64(chronos.Moment.now().epochNanoSeconds div 1_000_000)

proc setupProviders(ctx: BrokerContext): Result[void, string] =
  ## Set up broker providers on the library's processing thread.
  gProviderCtx = ctx
  gNextDeviceId = 1
  gNextSensorId = 100
  gDevices = @[]

  # InitializeRequest provider
  let initializeProviderRes = InitializeRequest.setProvider(
    ctx,
    proc(
        configPath: string
    ): Future[Result[InitializeRequest, string]] {.closure, async.} =
      gConfigPath = configPath
      gInitialized = true
      return ok(InitializeRequest(configPath: configPath, initialized: true)),
  )
  if initializeProviderRes.isErr():
    return err(
      "failed to register InitializeRequest provider: " & initializeProviderRes.error()
    )

  # ShutdownRequest provider
  let shutdownProviderRes = ShutdownRequest.setProvider(
    ctx,
    proc(): Future[Result[ShutdownRequest, string]] {.closure, async.} =
      gInitialized = false
      gDevices = @[]
      return ok(ShutdownRequest(status: 0)),
  )
  if shutdownProviderRes.isErr():
    return
      err("failed to register ShutdownRequest provider: " & shutdownProviderRes.error())

  # AddDevice provider
  let addDeviceProviderRes = AddDevice.setProvider(
    ctx,
    proc(
        devices: seq[AddDeviceSpec]
    ): Future[Result[AddDevice, string]] {.closure, async.} =
      if not gInitialized:
        return err("Library not initialized")
      var addedDevices: seq[DeviceInfo] = @[]
      for device in devices:
        let id = gNextDeviceId
        inc gNextDeviceId
        gDevices.add(
          Device(
            id: id,
            name: device.name,
            deviceType: device.deviceType,
            address: device.address,
            online: true,
          )
        )
        addedDevices.add(
          DeviceInfo(
            deviceId: id,
            name: device.name,
            deviceType: device.deviceType,
            address: device.address,
            online: true,
          )
        )
        await DeviceDiscovered.emit(
          gProviderCtx,
          DeviceDiscovered(
            deviceId: id,
            name: device.name,
            deviceType: device.deviceType,
            address: device.address,
          ),
        )
      return ok(AddDevice(devices: addedDevices, success: true)),
  )
  if addDeviceProviderRes.isErr():
    return err("failed to register AddDevice provider: " & addDeviceProviderRes.error())

  # RemoveDevice provider
  let removeDeviceProviderRes = RemoveDevice.setProvider(
    ctx,
    proc(deviceId: int64): Future[Result[RemoveDevice, string]] {.closure, async.} =
      if not gInitialized:
        return err("Library not initialized")
      for i in 0 ..< gDevices.len:
        if gDevices[i].id == deviceId:
          let dev = gDevices[i]
          gDevices.del(i)
          # Emit status change (offline)
          await DeviceStatusChanged.emit(
            gProviderCtx,
            DeviceStatusChanged(
              deviceId: dev.id, name: dev.name, online: false, timestampMs: nowMs()
            ),
          )
          return ok(RemoveDevice(success: true))
      return err("Device not found: " & $deviceId),
  )
  if removeDeviceProviderRes.isErr():
    return err(
      "failed to register RemoveDevice provider: " & removeDeviceProviderRes.error()
    )

  # GetDevice provider
  let getDeviceProviderRes = GetDevice.setProvider(
    ctx,
    proc(deviceId: int64): Future[Result[GetDevice, string]] {.closure, async.} =
      if not gInitialized:
        return err("Library not initialized")
      for dev in gDevices:
        if dev.id == deviceId:
          return ok(
            GetDevice(
              deviceId: dev.id,
              name: dev.name,
              deviceType: dev.deviceType,
              address: dev.address,
              online: dev.online,
            )
          )
      return err("Device not found: " & $deviceId),
  )
  if getDeviceProviderRes.isErr():
    return err("failed to register GetDevice provider: " & getDeviceProviderRes.error())

  # ListDevices provider
  let listDevicesProviderRes = ListDevices.setProvider(
    ctx,
    proc(): Future[Result[ListDevices, string]] {.closure, async.} =
      if not gInitialized:
        return err("Library not initialized")
      var infos: seq[DeviceInfo] = @[]
      for dev in gDevices:
        infos.add(
          DeviceInfo(
            deviceId: dev.id,
            name: dev.name,
            deviceType: dev.deviceType,
            address: dev.address,
            online: dev.online,
          )
        )
      return ok(ListDevices(devices: infos)),
  )
  if listDevicesProviderRes.isErr():
    return
      err("failed to register ListDevices provider: " & listDevicesProviderRes.error())

  # GetSensorData provider — returns synthetic raw bytes + enum status
  let getSensorDataProviderRes = GetSensorData.setProvider(
    ctx,
    proc(deviceId: int64): Future[Result[GetSensorData, string]] {.closure, async.} =
      if not gInitialized:
        return err("Library not initialized")
      var found = false
      for dev in gDevices:
        if dev.id == deviceId:
          found = true
          break
      if not found:
        return err("Device not found: " & $deviceId)
      let sid = SensorId(gNextSensorId)
      inc gNextSensorId
      # Emit a sensor alert (online status)
      await SensorAlert.emit(
        gProviderCtx,
        SensorAlert(
          sensorId: sid,
          deviceId: deviceId,
          status: dsOnline,
          timestampMs: Timestamp(nowMs()),
        ),
      )
      # Synthetic 8-byte sensor reading
      let raw: seq[byte] = @[0xDE'u8, 0xAD, 0xBE, 0xEF, 0x01, 0x02, 0x03, 0x04]
      return ok(GetSensorData(sensorId: sid, rawData: raw, status: dsOnline)),
  )
  if getSensorDataProviderRes.isErr():
    return err(
      "failed to register GetSensorData provider: " & getSensorDataProviderRes.error()
    )

  # GetDeviceTags provider — returns string labels for a device
  let getDeviceTagsProviderRes = GetDeviceTags.setProvider(
    ctx,
    proc(deviceId: int64): Future[Result[GetDeviceTags, string]] {.closure, async.} =
      if not gInitialized:
        return err("Library not initialized")
      for dev in gDevices:
        if dev.id == deviceId:
          return ok(GetDeviceTags(tags: @["monitored", "production", dev.deviceType]))
      return err("Device not found: " & $deviceId),
  )
  if getDeviceTagsProviderRes.isErr():
    return err(
      "failed to register GetDeviceTags provider: " & getDeviceTagsProviderRes.error()
    )

  # GetDeviceCapabilities provider — returns a fixed-size capability array
  let getDeviceCapabilitiesProviderRes = GetDeviceCapabilities.setProvider(
    ctx,
    proc(
        deviceId: int64
    ): Future[Result[GetDeviceCapabilities, string]] {.closure, async.} =
      if not gInitialized:
        return err("Library not initialized")
      for dev in gDevices:
        if dev.id == deviceId:
          # cap[0]=maxRate, cap[1]=bufSize, cap[2]=channels, cap[3]=flags
          let caps: array[4, int32] = [1000'i32, 4096'i32, 8'i32, 0x03'i32]
          return ok(
            GetDeviceCapabilities(capabilities: caps, capturedAt: Timestamp(nowMs()))
          )
      return err("Device not found: " & $deviceId),
  )
  if getDeviceCapabilitiesProviderRes.isErr():
    return err(
      "failed to register GetDeviceCapabilities provider: " &
        getDeviceCapabilitiesProviderRes.error()
    )

  ok()

# ---------------------------------------------------------------------------
# Library registration — MUST be last
# ---------------------------------------------------------------------------

registerBrokerLibrary:
  name:
    "mylib"
  initializeRequest:
    InitializeRequest
  shutdownRequest:
    ShutdownRequest

{.pop.}
